// Use Code node with n8n's $http helper for proper HTTP requests
const items = $input.all();

// Prepare the request payload
const payload = {
  content_id: `test_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
  domain: 'finance',
  prompt: 'Write a comprehensive analysis of current market trends and their implications for investors.',
  style_parameters: {
    tone: 'professional',
    complexity: 'intermediate',
    structure: 'analysis',
    length: 'medium',
    perspective: 'third-person'
  },
  source_metadata: {
    title: 'Market Trends Analysis Test',
    description: 'Testing content generation with comprehensive market data',
    url: 'https://example.com/market-trends',
    pub_date: new Date().toISOString()
  }
};

console.log('Preparing to call content generation API with payload:', JSON.stringify(payload, null, 2));

// Make HTTP request using n8n's $http helper
try {
  const response = await $http.request({
    method: 'POST',
    url: 'http://localhost:8010/api/v1/content/generate',
    headers: {
      'Content-Type': 'application/json',
      'X-Request-ID': payload.content_id
    },
    data: payload,
    timeout: 30000
  });

  console.log(`API Response Status: ${response.status}`);
  console.log('Content generation successful:', response.data.content_id);

  return [{
    json: {
      success: true,
      api_response: response.data,
      request_payload: payload,
      status: response.status,
      timestamp: new Date().toISOString()
    }
  }];

} catch (error) {
  console.error('Request failed:', error.message);

  const errorDetails = error.response ? {
    status: error.response.status,
    data: error.response.data
  } : error.message;

  return [{
    json: {
      success: false,
      error: 'API request failed',
      error_details: errorDetails,
      request_payload: payload,
      timestamp: new Date().toISOString()
    }
  }];
}
